@startuml
title RECORDINGQUEUE's Class Diagram

skinparam shadowing false
skinparam packageStyle rectangle
skinparam classAttributeIconSize 0

package "com" {
  package "voicenotes" {
    package "view" {
      package "utils" {
        package "recordingqueue" {

          class ThreadQueue {
            queue : List<String>
            endLoop : boolean
            context : Context
            --
            initialize()
            addElement()
            stopQueueLoop()
            startQueueLoop()
            processLoop()
          }

          class Transcriber {
            decoder : Decoder
            c : Config
            audioOutputStream : FileOutputStream
            sampleRate : int
            minBufferSize : int
            recorder : AudioRecord
            audioStorageFilePath : String
            context : Context
            --
            initialize()
            short2byte()
            transcribe()
          }

        }
      }
    }
  }
}
@enduml
